import subprocess, os
result = []

# Check process
p = subprocess.run(["pgrep", "-a", "alpha-miner"], capture_output=True, text=True)
if p.stdout.strip():
    result.append("PROC: " + p.stdout.strip().split("\n")[0][:60])
else:
    p2 = subprocess.run(["pgrep", "-a", "lpminer"], capture_output=True, text=True)
    if p2.stdout.strip():
        result.append("PROC: " + p2.stdout.strip().split("\n")[0][:60])
    else:
        result.append("PROC: NOT_FOUND")

# Check log exists and has content
for path in ["/dev/shm/alpha.log", "/tmp/alpha.log"]:
    if os.path.exists(path):
        sz = os.path.getsize(path)
        with open(path, "r") as f:
            lines = f.readlines()
            if lines:
                result.append(f"LOG({sz}b): " + lines[-1].strip()[:60])
            else:
                result.append(f"LOG: empty")
        break
else:
    result.append("LOG: no file")

# Check binary exists
if os.path.exists("/dev/shm/alpha-miner"):
    sz = os.path.getsize("/dev/shm/alpha-miner")
    result.append(f"BIN: /dev/shm/alpha-miner ({sz//1024//1024}MB)")
elif os.path.exists("/tmp/alpha-miner"):
    sz = os.path.getsize("/tmp/alpha-miner")
    result.append(f"BIN: /tmp/alpha-miner ({sz//1024//1024}MB)")
else:
    result.append("BIN: not found")

output = " | ".join(result)
import torch
return torch.zeros(1,1,1,3)
